            *maxi = s;
        }
    } else {
        for (int i = l; i <= r; i++) {
            swap(&arr[l], &arr[i]);
            permute(arr, l + 1, r, l_val, maxi);
            swap(&arr[l], &arr[i]);
        }
    }
}

